import{_ as n,o as a,c as e,ak as p}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"CI/CD","description":"","frontmatter":{},"headers":[],"relativePath":"devops/cicd/index.md","filePath":"devops/cicd/index.md","lastUpdated":1774320699000}'),i={name:"devops/cicd/index.md"};function l(t,s,r,c,d,o){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to “CI/CD”">​</a></h1><p>从代码提交到生产部署，流水线是软件交付的血管。</p><p>很多人以为 CI/CD 就是「写个脚本自动部署」，但真正做下来会发现：代码质量门禁怎么设？构建缓存怎么利用？制品怎么管理？安全扫描放哪个阶段？回滚怎么做才能不影响用户？</p><p>这些问题没有标准答案，但有一些经过无数团队验证的最佳实践。这篇文章系列覆盖 Git 版本控制、Jenkins 流水线、现代 CI/CD 工具（GitLab CI、GitHub Actions、ArgoCD、Tekton），以及完整的 CI/CD 最佳实践，帮你搭建一套真正能落地的交付体系。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>CI/CD 的生态非常丰富，从老牌的 Jenkins 到云原生的 Tekton，每种工具都有自己的适用场景。</p><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/cicd/git-workflow">Git 与版本控制</a></td><td>5 篇</td><td>Git Flow、命令原理、提交规范、Hooks</td></tr><tr><td><a href="/devops/cicd/jenkins-architecture">Jenkins</a></td><td>5 篇</td><td>架构原理、Declarative Pipeline、插件生态</td></tr><tr><td><a href="/devops/cicd/gitlab-ci">现代 CI/CD 工具</a></td><td>6 篇</td><td>GitLab CI、GitHub Actions、ArgoCD、Tekton、Spinnaker</td></tr><tr><td><a href="/devops/cicd/pipeline-design">CI/CD 最佳实践</a></td><td>7 篇</td><td>流水线设计、代码质量、制品管理、安全扫描</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：Git 基础（2-3 天）</span></span>
<span class="line"><span>→ 掌握 Git Flow / GitHub Flow 工作流</span></span>
<span class="line"><span>→ 深入理解 merge、rebase、cherry-pick、stash</span></span>
<span class="line"><span>→ 规范化提交信息：Conventional Commits</span></span>
<span class="line"><span>→ 配置 Git Hooks 实现提交前检查</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：Jenkins 入门（1 周）</span></span>
<span class="line"><span>→ 搭建 Master-Slave 架构</span></span>
<span class="line"><span>→ 编写 Jenkinsfile 声明式流水线</span></span>
<span class="line"><span>→ 集成 Docker 构建镜像</span></span>
<span class="line"><span>→ 集成 SonarQube 做代码质量检查</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：现代 CI/CD 工具（1 周）</span></span>
<span class="line"><span>→ GitHub Actions 工作流配置</span></span>
<span class="line"><span>→ GitLab CI 流水线语法</span></span>
<span class="line"><span>→ ArgoCD GitOps 实践</span></span>
<span class="line"><span>→ Tekton 入门（Kubernetes 原生 CI/CD）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：工程化提升（1 周）</span></span>
<span class="line"><span>→ 多环境部署策略（蓝绿、金丝雀）</span></span>
<span class="line"><span>→ 镜像安全扫描（Trivy、Clair）</span></span>
<span class="line"><span>→ 制品库设计与 Nexus/Harbor 集成</span></span>
<span class="line"><span>→ 完整的端到端流水线搭建</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="ci-和-cd-的本质区别" tabindex="-1">CI 和 CD 的本质区别 <a class="header-anchor" href="#ci-和-cd-的本质区别" aria-label="Permalink to “CI 和 CD 的本质区别”">​</a></h2><p>很多人把 CI/CD 当成一个词，但它们解决的是不同的问题：</p><ul><li><strong>CI（持续集成）</strong>：代码合并到主干后，自动跑构建、单元测试、代码扫描。目标是尽早发现集成错误，保证代码质量。核心衡量指标是「构建成功率」和「平均构建时间」。</li><li><strong>CD（持续交付/部署）</strong>：把通过测试的代码，自动部署到各个环境（测试、预生产）。目标是让软件随时处于可发布状态。核心衡量指标是「部署频率」和「变更前置时间」。</li></ul><p>没有扎实的 CI，CD 就是空中楼阁。很多团队的 CD 流水线看起来很美，但三天两头构建失败，根本原因在 CI 阶段没做好质量门禁。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>CI/CD 面试的核心，在于考察你对「软件交付全流程」的理解：</p><ol><li><strong>流程设计</strong>：你能设计一个完整的 CI/CD 流水线吗？每个阶段做什么？质量门禁怎么设置？</li><li><strong>工具选型</strong>：Jenkins vs GitLab CI vs GitHub Actions，你选哪个？为什么？</li><li><strong>问题排查</strong>：构建失败怎么排查？流水线跑得慢怎么优化？</li><li><strong>安全意识</strong>：镜像扫描放在哪个阶段？制品库怎么管理权限？</li><li><strong>部署策略</strong>：蓝绿部署和金丝雀发布的区别是什么？什么时候用哪个？</li></ol><blockquote><p>&quot;CI/CD 流水线就像一条生产线，面试官想知道的是：你有没有站在生产线外面看过全局，理解每个环节为什么要这样设计。&quot;</p></blockquote>`,17)])])}const C=n(i,[["render",l]]);export{h as __pageData,C as default};
